const input = $json;

const chatInput =
  input.chatInput ||
  input.text ||
  input.message ||
  input.input ||
  '';

const chatSessionId =
  input.sessionId ||
  input.chatSessionId ||
  input.chat_id ||
  input.conversationId ||
  'manual_chat_session';

const text = String(chatInput || '').trim();

const numberCommandMatch = text.match(/^\/(?:numero|número|phone)\s+(\+?\d[\d\s+-]*)$/i);

let requestedPhone = null;

if (numberCommandMatch) {
  requestedPhone = numberCommandMatch[1].replace(/\D/g, '');

  // Si colocas 949186386, lo convierte a 56949186386
  if (!requestedPhone.startsWith('56') && requestedPhone.length === 9) {
    requestedPhone = `56${requestedPhone}`;
  }
}

return [
  {
    json: {
      raw_chat_payload: input,
      chat_session_id: chatSessionId,
      text,
      is_number_command: Boolean(requestedPhone),
      requested_phone: requestedPhone,
      timestamp: new Date().toISOString()
    }
  }
];

const chatInput = $('parse_chat_input').first().json;
const session = $json;

const phone = String(session.assigned_phone || '').replace(/\D/g, '');

if (!phone || !phone.startsWith('56')) {
  throw new Error('Invalid assigned_phone for n8n_chat test session');
}

const now = new Date().toISOString();

return [
  {
    json: {
      channel: 'n8n_chat',
      lead_id: phone,
      phone,
      message_id: `n8n_chat_${chatInput.chat_session_id}_${Date.now()}`,
      timestamp: now,
      message_type: 'text',
      text: chatInput.text,
      attachments: [],
      contact: {
        wa_id: phone,
        name: session.assigned_name || `Test Chat ${phone}`
      },
      source_metadata: {
        provider: 'n8n_chat',
        chat_session_id: chatInput.chat_session_id,
        assigned_phone: phone,
        test_mode: true
      },
      raw_message: {
        chat_session_id: chatInput.chat_session_id,
        text: chatInput.text
      }
    }
  }
];

return [
  {
    json: {
      output: `Listo. Este chat ahora simula el número ${$json.assigned_phone}.`
    }
  }
];

return [
  {
    json: {
      output: `Primero asigna un número para este chat usando:\n\n/numero 569900000001`
    }
  }
];

const row = $json;

const message =
  row.content ||
  row.message ||
  row.output ||
  null;

if (!message) {
  return [
    {
      json: {
        output: "No encontré una respuesta generada por el bot. Revisa si el action_executor llegó a enviar/guardar el mensaje outbound."
      }
    }
  ];
}

return [
  {
    json: {
      output: message
    }
  }
];

